import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Manages tasks, assignments, and task-related operations within projects.',

  dependencies: {
    modules: ['auth'], // Depends on auth for user/session types and functions
  },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/:taskId/assign', auth: true },
      // Other task routes would go here
    ],
    functions: ['assignTask'], // A service function that the route handler might use
    types: ['Task', 'TaskAssignmentError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: tasks table',
    'reads from: team_members table',
  ],

  invariants: [
    'A task must always belong to exactly one team',
    'Only team members can be assigned to a task',
    'A task can only have one assignee at a time',
  ],
});

// Placeholder types for the contract
export type Task = {
  id: string;
  title: string;
  description?: string;
  teamId: string;
  assigneeId?: string;
  status: 'todo' | 'in-progress' | 'done';
  createdAt: Date;
  updatedAt: Date;
};

export type TaskAssignmentError =
  | 'TASK_NOT_FOUND'
  | 'ASSIGNEE_NOT_TEAM_MEMBER'
  | 'INVALID_INPUT'
  | 'DATABASE_ERROR'
  | 'UNAUTHORIZED';
